import torch
from torch.utils.cpp_extension import load_inline

NUM_ATTENTION_HEADS = 80
NUM_KEY_VALUE_HEADS = 8
HEAD_DIM = 128
NUM_GROUPS = NUM_ATTENTION_HEADS // NUM_KEY_VALUE_HEADS  # 10

_cuda_source = r"""
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <cublas_v2.h>
#include <stdio.h>

// Warp-level reduction
__device__ __forceinline__ float warp_reduce_sum(float val) {
    for (int offset = 16; offset > 0; offset >>= 1)
        val += __shfl_down_sync(0xffffffff, val, offset);
    return val;
}

// Fused dropout backward + softmax backward kernel
// One warp (32 threads) per row
// Each row has skv elements
__global__ void fused_dropout_softmax_bwd_kernel(
    const __nv_bfloat16* __restrict__ dP_dropped,  // [N_rows, skv]
    const __nv_bfloat16* __restrict__ P,            // [N_rows, skv]
    const bool* __restrict__ mask,                   // [N_rows, skv]
    __nv_bfloat16* __restrict__ dS,                 // [N_rows, skv]
    int skv,
    float scale
) {
    int row = blockIdx.x;
    int lane = threadIdx.x;  // 0..31
    int warp_id = threadIdx.y; // for multiple warps per block if needed

    const __nv_bfloat16* dP_row = dP_dropped + row * skv;
    const __nv_bfloat16* P_row = P + row * skv;
    const bool* mask_row = mask + row * skv;
    __nv_bfloat16* dS_row = dS + row * skv;

    // Two-pass: first compute sum(dP * P), then compute dS
    // Use shared memory for the sum
    extern __shared__ float shared_sum[];

    // Pass 1: compute sum(dP * P) where dP = mask ? dP_dropped * scale : 0
    float local_sum = 0.0f;
    for (int i = lane; i < skv; i += 32) {
        float dp_d = __bfloat162float(dP_row[i]);
        float p_val = __bfloat162float(P_row[i]);
        float dp = mask_row[i] ? dp_d * scale : 0.0f;
        local_sum += dp * p_val;
    }
    local_sum = warp_reduce_sum(local_sum);
    if (lane == 0) shared_sum[warp_id] = local_sum;
    __syncthreads();
    float sum_dPP = shared_sum[warp_id];

    // Pass 2: compute dS = P * (dP - sum_dPP)
    for (int i = lane; i < skv; i += 32) {
        float dp_d = __bfloat162float(dP_row[i]);
        float p_val = __bfloat162float(P_row[i]);
        float dp = mask_row[i] ? dp_d * scale : 0.0f;
        float ds = p_val * (dp - sum_dPP);
        dS_row[i] = __float2bfloat16(ds);
    }
}

// Multiple warps per block version for larger skv
__global__ void fused_dropout_softmax_bwd_kernel_mw(
    const __nv_bfloat16* __restrict__ dP_dropped,
    const __nv_bfloat16* __restrict__ P,
    const bool* __restrict__ mask,
    __nv_bfloat16* __restrict__ dS,
    int skv,
    float scale
) {
    // blockDim.x = 32 (warp), blockDim.y = num_warps_per_row
    // Each block handles one row, multiple warps collaborate
    int row = blockIdx.x;
    int lane = threadIdx.x;
    int warp_id = threadIdx.y;
    int num_warps = blockDim.y;

    const __nv_bfloat16* dP_row = dP_dropped + row * skv;
    const __nv_bfloat16* P_row = P + row * skv;
    const bool* mask_row = mask + row * skv;
    __nv_bfloat16* dS_row = dS + row * skv;

    extern __shared__ float shared_sum[];

    // Pass 1
    float local_sum = 0.0f;
    int stride = 32 * num_warps;
    int start = warp_id * 32 + lane;
    for (int i = start; i < skv; i += stride) {
        float dp_d = __bfloat162float(dP_row[i]);
        float p_val = __bfloat162float(P_row[i]);
        float dp = mask_row[i] ? dp_d * scale : 0.0f;
        local_sum += dp * p_val;
    }
    local_sum = warp_reduce_sum(local_sum);
    if (lane == 0) shared_sum[warp_id] = local_sum;
    __syncthreads();

    // Reduce across warps
    float total_sum = 0.0f;
    for (int w = 0; w < num_warps; w++) total_sum += shared_sum[w];

    // Pass 2
    for (int i = start; i < skv; i += stride) {
        float dp_d = __bfloat162float(dP_row[i]);
        float p_val = __bfloat162float(P_row[i]);
        float dp = mask_row[i] ? dp_d * scale : 0.0f;
        float ds = p_val * (dp - total_sum);
        dS_row[i] = __float2bfloat16(ds);
    }
}


// cuBLAS handle - module-level
static cublasHandle_t cublas_handle = nullptr;

void ensure_cublas() {
    if (cublas_handle == nullptr) {
        cublasCreate(&cublas_handle);
        cublasSetMathMode(cublas_handle, CUBLAS_DEFAULT_MATH);
    }
}

// BMM1: dP_dropped = dO @ V^T
// dO: [bs, 8, 10, sq, 128] bf16
// V:  [bs, 8, skv, 128] bf16 -> V^T: [bs, 8, 128, skv]
// dP: [bs, 8, 10, sq, skv] bf16
// We treat it as [bs*8*10, sq, 128] @ [bs*8, 128, skv] with stride tricks
// For each kv_head k in [0,8), and group g in [0,10):
//   dP[b, k, g, :, :] = dO[b, k, g, :, :] @ V[b, k, :, :]^T
// This is a batched GEMM with batch = bs*8*10
// dO stride: (8*10*sq*128, 10*sq*128, sq*128, 128, 1) -> batch stride = sq*128 (between groups)
// V^T: for group g, same V[b,k] -> stride 0 between groups

std::vector<torch::Tensor> attn_bwd_cuda(
    torch::Tensor dO,         // [bs, 80, sq, 128] bf16 contiguous
    torch::Tensor P,          // [bs, 80, sq, skv] bf16
    torch::Tensor P_dropped,  // [bs, 80, sq, skv] bf16
    torch::Tensor V,          // [bs, 8, skv, 128] bf16
    torch::Tensor mask,       // [bs, 80, sq, skv] bool
    float p_drop
) {
    ensure_cublas();

    auto stream = at::cuda::getCurrentCUDAStream();
    cublasSetStream(cublas_handle, stream);

    int bs = dO.size(0);
    int sq = dO.size(2);
    int skv = V.size(2);

    // Reshape dO to [bs, 8, 10, sq, 128]
    auto dO_grouped = dO.reshape({bs, NUM_KEY_VALUE_HEADS, NUM_GROUPS, sq, HEAD_DIM});

    // Allocate dP_dropped output: [bs, 80, sq, skv]
    auto dP_dropped_out = torch::empty({bs, NUM_ATTENTION_HEADS, sq, skv}, 
                                        dO.options());
    auto dP_grouped = dP_dropped_out.reshape({bs, NUM_KEY_VALUE_HEADS, NUM_GROUPS, sq, skv});

    // Allocate dV: [bs, 8, skv, 128]
    auto dV_out = torch::zeros({bs, NUM_KEY_VALUE_HEADS, skv, HEAD_DIM}, 
                                dO.options().dtype(torch::kFloat32));

    // Use PyTorch's batched matmul for BMM1 and BMM2 via cuBLAS
    // BMM1: dP_grouped = dO_grouped @ V^T
    // V: [bs, 8, skv, 128] -> expand to [bs, 8, 1, skv, 128] -> [bs, 8, 10, skv, 128]
    // Then transpose last two dims for matmul
    // dO_grouped: [bs, 8, 10, sq, 128] @ V_t: [bs, 8, 10, 128, skv] = [bs, 8, 10, sq, skv]

    auto V_t = V.transpose(-2, -1).unsqueeze(2).expand({bs, NUM_KEY_VALUE_HEADS, NUM_GROUPS, HEAD_DIM, skv});
    // Note: expand doesn't allocate, matmul will handle it
    // But we need contiguous for cuBLAS... use PyTorch's matmul which handles expand

    // Use torch::matmul which handles broadcasting efficiently
    auto dP_grouped_computed = torch::matmul(dO_grouped, V.transpose(-2, -1).unsqueeze(2));
    // dP_grouped_computed: [bs, 8, 10, sq, skv]
    dP_dropped_out = dP_grouped_computed.reshape({bs, NUM_ATTENTION_HEADS, sq, skv}).contiguous();

    // Fused dropout backward + softmax backward
    auto dS = torch::empty({bs, NUM_ATTENTION_HEADS, sq, skv}, dO.options());

    float scale = 1.0f / (1.0f - p_drop);
    int n_rows = bs * NUM_ATTENTION_HEADS * sq;

    // Make contiguous
    auto dP_cont = dP_dropped_out.contiguous();
    auto P_cont = P.contiguous();
    auto mask_cont = mask.contiguous();

    if (skv <= 256) {
        int num_warps = 1;
        dim3 block(32, num_warps);
        dim3 grid(n_rows);
        int smem = num_warps * sizeof(float);
        fused_dropout_softmax_bwd_kernel<<<grid, block, smem, stream>>>(
            (__nv_bfloat16*)dP_cont.data_ptr(),
            (__nv_bfloat16*)P_cont.data_ptr(),
            (bool*)mask_cont.data_ptr(),
            (__nv_bfloat16*)dS.data_ptr(),
            skv, scale
        );
    } else {
        int num_warps = std::min(8, (skv + 255) / 256);
        dim3 block(32, num_warps);
        dim3 grid(n_rows);
        int smem = num_warps * sizeof(float);
        fused_dropout_softmax_bwd_kernel_mw<<<grid, block, smem, stream>>>(
            (__nv_bfloat16*)dP_cont.data_ptr(),
            (__nv_bfloat16*)P_cont.data_ptr(),
            (bool*)mask_cont.data_ptr(),
            (__nv_bfloat16*)dS.data_ptr(),
            skv, scale
        );
    }

    // BMM2: dV = P_dropped^T @ dO, sum over groups
    // P_dropped: [bs, 80, sq, skv] -> [bs, 8, 10, sq, skv]
    auto P_dropped_grouped = P_dropped.reshape({bs, NUM_KEY_VALUE_HEADS, NUM_GROUPS, sq, skv});
    // [bs, 8, 10, skv, sq] @ [bs, 8, 10, sq, 128] = [bs, 8, 10, skv, 128]
    auto dV_grouped = torch::matmul(
        P_dropped_grouped.transpose(-2, -1),
        dO_grouped
    );
    // Sum over groups: [bs, 8, 10, skv, 128] -> [bs, 8, skv, 128]
    auto dV = dV_grouped.to(torch::kFloat32).sum(2).to(torch::kBFloat16);

    return {dS, dV};
}
