#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <ATen/cuda/CUDAContext.h>

__device__ __forceinline__ float warp_reduce_sum(float val) {
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1)
        val += __shfl_down_sync(0xffffffff, val, offset);
    return val;
}

// One block per row, blockDim.x=32 (one warp), blockDim.y=num_warps
// Handles variable skv without recompilation
__global__ void fused_dropout_softmax_bwd(
    const __nv_bfloat16* __restrict__ dP_dropped,
    const __nv_bfloat16* __restrict__ P,
    const bool* __restrict__ mask,
    __nv_bfloat16* __restrict__ dS,
    int skv,
    float scale
) {
    int row = blockIdx.x;
    int lane = threadIdx.x;   // 0..31
    int wid  = threadIdx.y;   // warp index within block
    int nw   = blockDim.y;    // number of warps per block

    const __nv_bfloat16* dP_row = dP_dropped + (long)row * skv;
    const __nv_bfloat16* P_row  = P          + (long)row * skv;
    const bool*          m_row  = mask        + (long)row * skv;
    __nv_bfloat16*       dS_row = dS          + (long)row * skv;

    extern __shared__ float smem[];  // [nw] floats

    // Pass 1: accumulate sum(dP * P)
    float local_sum = 0.0f;
    int tid = wid * 32 + lane;
    int stride = nw * 32;
    for (int i = tid; i < skv; i += stride) {
        float dp_d = __bfloat162float(dP_row[i]);
        float p    = __bfloat162float(P_row[i]);
        float dp   = m_row[i] ? dp_d * scale : 0.0f;
        local_sum += dp * p;
    }
    // Warp reduce
    local_sum = warp_reduce_sum(local_sum);
    if (lane == 0) smem[wid] = local_sum;
    __syncthreads();

    // Block reduce across warps (done by warp 0)
    float total = 0.0f;
    if (wid == 0) {
        float v = (lane < nw) ? smem[lane] : 0.0f;
        v = warp_reduce_sum(v);
        if (lane == 0) smem[0] = v;
    }
    __syncthreads();
    total = smem[0];

    // Pass 2: write dS
    for (int i = tid; i < skv; i += stride) {
        float dp_d = __bfloat162float(dP_row[i]);
        float p    = __bfloat162float(P_row[i]);
        float dp   = m_row[i] ? dp_d * scale : 0.0f;
        dS_row[i]  = __float2bfloat16(p * (dp - total));
    }
}

