    # Reshape dP to [bs*80*sq, skv] for kernel
    dP_dropped_flat = dP_grouped.reshape(bs * NUM_ATTENTION_HEADS * sq, skv).contiguous()
    P_flat = attn_weights.reshape(bs * NUM_ATTENTION_HEADS * sq, skv).contiguous()
    mask_flat = dropout_mask.reshape(bs * NUM_ATTENTION_HEADS * sq, skv).contiguous()

